1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Damage {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface Incident {
18	  cause: string;
19	  damages: Damage[];
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: Incident;
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: { yearsWithMHPCO: number };
32	  steps: Step[];
33	}
34	
35	const BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	};
41	
42	const COMPONENT_PREMIUM = 25;
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const INSURANCE_VALUE: Record<string, number> = {
48	  sword: 1000,
49	  amulet: 600,
50	  staff: 800,
51	  potion: 400,
52	};
53	const COMPONENT_INSURANCE_VALUE = 250;
54	
55	const DEDUCTIBLE = 100;
56	const CAP_MULTIPLIER = 2;
57	const HALF_REIMBURSEMENT_ENCHANTMENT = 8;
58	const HALF_REIMBURSEMENT_RATE = 0.5;
59	
60	const FIRST_INSURANCE_SURCHARGE = 1.1;
61	const CURSE_SURCHARGE_RATE = 0.5;
62	const HIGH_ENCHANTMENT_THRESHOLD = 5;
63	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
64	const LOYALTY_THRESHOLD_YEARS = 2;
65	const LOYALTY_DISCOUNT_RATE = 0.2;
66	const FOLLOWUP_DISCOUNT_RATE = 0.15;
67	const PROCESSING_FEE = 5;
68	
69	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
70	
71	const isKnownType = (type: string): boolean => type in BASE_PREMIUM || COMPONENT_TYPES.has(type);
72	
73	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
74	
75	// Base premium of a single item (main item or one component).
76	const itemBase = (item: Item): number =>
77	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
78	
79	// A surcharge adds `rate` of the base premium for each affected item.
80	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
81	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
82	
83	// Curse adds 50% of the affected item's base premium.
84	const curseSurcharge = (items: Item[]): number =>
85	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
86	
87	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
88	const enchantmentSurcharge = (items: Item[]): number =>
89	  surchargeFor(
90	    items,
91	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
92	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
93	  );
94	
95	// Base premium for `count` alike components: a group of exactly 3 forms a
96	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
97	// COMPONENT_PREMIUM.
98	const componentGroupPremium = (count: number): number =>
99	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
100	
101	// Count how many alike components of each type appear (e.g. { rune: 2 }).
102	const countByType = (items: Item[]): Map<string, number> =>
103	  items.reduce((counts, item) => {
104	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
105	    return counts;
106	  }, new Map<string, number>());
107	
108	const mainItemsPremium = (items: Item[]): number =>
109	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
110	
111	const componentsPremium = (items: Item[]): number =>
112	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
113	
114	const basePremium = (items: Item[]): number =>
115	  mainItemsPremium(items) + componentsPremium(items);
116	
117	// Insurance value of a single item (main item or one component).
118	const insuranceValue = (item: Item): number =>
119	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUE[item.type] ?? 0);
120	
121	// Snap away floating-point noise (e.g. 197.5000000001) by rounding to 6
122	// decimal places, so a subsequent ceil/floor lands on the intended whole G.
123	const FLOAT_GUARD_PRECISION = 1e6;
124	const snapFloat = (value: number): number =>
125	  Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION;
126	
127	// Round up to a whole number in MHPCO's favour.
128	const roundUpToWhole = (value: number): number => Math.ceil(snapFloat(value));
129	
130	// Round a payout down to whole G, in MHPCO's favour.
131	const roundDownToWhole = (value: number): number => Math.floor(snapFloat(value));
132	
133	// A policy-wide discount takes `rate` of the policy base when it applies.
134	const discount = (applies: boolean, rate: number, base: number): number =>
135	  applies ? rate * base : 0;
136	
137	// Long-standing customers (>= 2 years) receive 20% off the policy base.
138	const loyaltyDiscount = (base: number, yearsWithMHPCO: number): number =>
139	  discount(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT_RATE, base);
140	
141	// Every quote after the customer's first receives 15% off the policy base.
142	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
143	  discount(isFollowUp, FOLLOWUP_DISCOUNT_RATE, base);
144	
145	// Reject a quote that includes any item MHPCO does not insure.
146	const assertKnownTypes = (items: Item[]): void => {
147	  const unknown = items.find((item) => !isKnownType(item.type));
148	  if (unknown) {
149	    throw new Error(`unknown item type: ${unknown.type}`);
150	  }
151	};
152	
153	// Premium for one quote: base premium plus the first-insurance surcharge,
154	// item-specific curse/enchantment surcharges, less the policy-wide loyalty
155	// and follow-up discounts, and the flat processing fee.
156	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
157	  assertKnownTypes(items);
158	  const base = basePremium(items);
159	  return (
160	    base * FIRST_INSURANCE_SURCHARGE +
161	    curseSurcharge(items) +
162	    enchantmentSurcharge(items) -
163	    loyaltyDiscount(base, yearsWithMHPCO) -
164	    followUpDiscount(base, isFollowUp) +
165	    PROCESSING_FEE
166	  );
167	};
168	
169	// Reimbursable amount for damage to one item: halved for highly enchanted
170	// items (>= 8), otherwise the full damage amount.
171	const reimbursement = (item: Item, amount: number): number =>
172	  (item.enchantment ?? 0) >= HALF_REIMBURSEMENT_ENCHANTMENT
173	    ? HALF_REIMBURSEMENT_RATE * amount
174	    : amount;
175	
176	// Payout for one damage event: reimbursement less the per-event deductible.
177	// A negative damage amount is invalid and rejected.
178	const damagePayout = (item: Item, damage: Damage): number => {
179	  if (damage.amount < 0) {
180	    throw new Error(`negative damage amount: ${damage.amount}`);
181	  }
182	  return Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
183	};
184	
185	// Pair each damage with a distinct policy item of the same type, consuming that
186	// item so it can back only one damage. A damage with no remaining matching item
187	// (not insured, or more damages of a type than the policy covers) is rejected.
188	const pairDamagesWithItems = (policy: Item[], damages: Damage[]): [Item, Damage][] => {
189	  const available = [...policy];
190	  return damages.map((damage): [Item, Damage] => {
191	    const index = available.findIndex((item) => item.type === damage.itemType);
192	    if (index === -1) {
193	      throw new Error(`damaged item not in policy: ${damage.itemType}`);
194	    }
195	    const [item] = available.splice(index, 1);
196	    return [item, damage];
197	  });
198	};
199	
200	// Total cap for a policy: twice the sum of its items' insurance values.
201	const policyCap = (policy: Item[]): number => CAP_MULTIPLIER * sum(policy.map(insuranceValue));
202	
203	// Payout for a claim against a policy with `remainingCap` left: the desired
204	// reimbursement (per-damage, deductible applied) limited to the remaining cap.
205	const claimResult = (
206	  policy: Item[],
207	  incident: Incident,
208	  remainingCap: number,
209	): { payout: number; remainingCap: number } => {
210	  const pairs = pairDamagesWithItems(policy, incident.damages);
211	  const desired = roundDownToWhole(
212	    sum(pairs.map(([item, damage]) => damagePayout(item, damage))),
213	  );
214	  const payout = Math.min(desired, remainingCap);
215	  return { payout, remainingCap: remainingCap - payout };
216	};
217	
218	// What MHPCO remembers about each policy it has quoted: the insured items and
219	// how much of the claim cap is still available.
220	interface Policy {
221	  items: Item[];
222	  remainingCap: number;
223	}
224	
225	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
226	  const { yearsWithMHPCO } = scenario.customer;
227	  const policiesByStep: Record<number, Policy> = {};
228	  let quotesSeen = 0;
229	  const results = scenario.steps.map((step, index) => {
230	    if (step.op === "claim") {
231	      const policy = policiesByStep[step.policy];
232	      const result = claimResult(policy.items, step.incident, policy.remainingCap);
233	      policy.remainingCap = result.remainingCap;
234	      return result;
235	    }
236	    const isFollowUp = quotesSeen > 0;
237	    quotesSeen += 1;
238	    policiesByStep[index] = { items: step.items, remainingCap: policyCap(step.items) };
239	    return { premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO, isFollowUp)) };
240	  });
241	  return { results };
242	};
243

1	import { runScenario } from "./claim-office.js";
2	
3	// Read a scenario as JSON from stdin, write its results as JSON to stdout.
4	// Any parse or processing error is reported on stderr with a non-zero exit.
5	let input = "";
6	process.stdin.setEncoding("utf8");
7	process.stdin.on("data", (chunk) => {
8	  input += chunk;
9	});
10	process.stdin.on("end", () => {
11	  try {
12	    const scenario = JSON.parse(input);
13	    process.stdout.write(JSON.stringify(runScenario(scenario)));
14	  } catch (error) {
15	    process.stderr.write(error instanceof Error ? error.message : String(error));
16	    process.exitCode = 1;
17	  }
18	});
